-- Documentation Translations Batch 1: ga, hr, it, lv
-- Run this in your Supabase SQL Editor

INSERT INTO ui_translations (lang, key, value)
VALUES 
  -- Irish (ga)
  ('ga', 'doc_welcome_title', 'Fáilte go Aliolo'),
  ('ga', 'doc_welcome_desc', 'Is ardán foghlama amhairc é Aliolo atá deartha chun cabhrú leat máistreacht a fháil ar ábhair trí chártaí splancacha agus tástáil idirghníomhach.'),
  ('ga', 'doc_pillars_title', 'Na 8 bPríomhcholún'),
  ('ga', 'doc_pillars_desc', 'Eagraítear an t-ábhar go léir in Aliolo i 8 gcolún bunúsacha: Acadúil & Gairmiúil, Domhan, Dúlra, Corp an Duine, Daonnachtaí, Fóillíocht, Innealtóireacht, agus Eile. Soláthraíonn na catagóirí seo creat struchtúrtha do gach ábhar ar fud an ardáin.'),
  ('ga', 'doc_leaderboard_title', 'Clár Ceannairí Domhanda'),
  ('ga', 'doc_leaderboard_desc', 'In iomaíocht le foghlaimeoirí ar fud an domhain! Puint XP a thuilleamh trí sheisiúin cártaí a chríochnú agus an rangú a dhreapadh. Déantar do phost a nuashonrú i bhfíor-am de réir mar a dhéanann tú máistreacht ar ábhair nua.'),
  ('ga', 'doc_friends_title', 'Cairde & Cuirí'),
  ('ga', 'doc_friends_desc', 'Is fearr foghlaim le chéile! Tabhair cuireadh do chairde chuig Aliolo trí do phróifíl. Is féidir leat dul chun cinn a chéile a rianú agus spreagadh a fháil trí fheiceáil cé a choinníonn an streak is faide.'),
  ('ga', 'doc_streaks_title', 'Córas Streak'),
  ('ga', 'doc_streaks_desc', 'Is í an chomhsheasmhacht an eochair! Críochnaigh do sprioc laethúil gach lá chun do streak a thógáil. Ná caill lá, nó athshocrófar an streak.'),
  ('ga', 'doc_goals_title', 'Spriocanna Laethúla'),
  ('ga', 'doc_goals_desc', 'Socraigh do sprioc críochnaithe cártaí laethúil sna socruithe. Tiocfaidh athruithe ar do sprioc i bhfeidhm ón lá dar gcionn.'),
  ('ga', 'doc_public_title', 'Poiblí vs Príobháideach'),
  ('ga', 'doc_public_desc', 'Is féidir le hábhair a bheith príobháideach (le feiceáil agat féin amháin) nó poiblí. Comhroinntear ábhar poiblí le pobal iomlán Aliolo, rud a ligeann do gach duine do chruthuithe a fháil amach agus foghlaim uathu.'),
  ('ga', 'doc_sync_title', 'Sioncronú Cloud'),
  ('ga', 'doc_sync_desc', 'Déantar do dhul chun cinn a shioncronú go huathoibríoch leis an néal. Is féidir leat aistriú idir leaganacha gréasáin agus deisce gan do streak a chailleadh.'),
  ('ga', 'doc_feedback_title', 'Córas Aiseolais'),
  ('ga', 'doc_feedback_desc', 'Cabhraigh linn feabhsú! Bain úsáid as an deilbhín aiseolais (Icons.feedback) ar aon Ábhar nó Fillteán chun fadhbanna a thuairisciú. Is féidir leat aiseolas ginearálta app a sheoladh freisin tríd an rannóg Tacaíochta.'),
  ('ga', 'doc_lang_title', 'Teanga Foghlama'),
  ('ga', 'doc_lang_desc', 'Roghnaigh do theanga foghlama is fearr leat i gcónaí sa roghchlár barr sula roghnaíonn tú ábhar. Cinntíonn sé seo go lódáiltear an fhuaim agus na haistriúcháin chearta.'),
  ('ga', 'doc_filters_title', 'Cuardach & Scagairí'),
  ('ga', 'doc_filters_desc', 'Faigh ábhar go tapa ag baint úsáide as an mbarra cuardaigh. Is féidir leat scagadh de réir Grúpa Aoise (Luath go hArdleibhéal) nó do radharc a chúngú go Bailiúcháin agus Fillteáin shonracha.'),
  ('ga', 'doc_flashcards_title', 'Cártaí Splancacha Amhairc'),
  ('ga', 'doc_flashcards_desc', 'Tá sraith cártaí i ngach ábhar. Cé go dtacaítear le híomhánna agus le fuaim, tá siad roghnach—is féidir leis an ábhar a bheith amhairc amháin nó ginte go dinimiciúil.'),
  ('ga', 'doc_study_modes_title', 'Modhanna Staidéir Oiriúnaitheacha'),
  ('ga', 'doc_study_modes_desc', 'Tacaíonn Aliolo le modhanna tástála éagsúla bunaithe ar do chuid ábhair: Íomhá-go-Téacs, Fuaim-go-hÍomhá, agus Téacs-go-Fuaim. Cinntíonn an cur chuige ilchéadfach seo go ndéanann tú máistreacht ar ábhair ó gach uillinn.'),
  ('ga', 'doc_testing_title', 'Tástáil Idirghníomhach'),
  ('ga', 'doc_testing_desc', 'Tabhair dúshlán duit féin le ceisteanna ilroghnacha (MCQ). Rachaidh an aip ar aghaidh go huathoibríoch agus tú ag freagairt, ag cabhrú leat foghlaim níos tapa.'),
  ('ga', 'doc_autoplay_title', 'Foghlaim Uath-imreoir'),
  ('ga', 'doc_autoplay_desc', 'Is féidir leis an aip dul ar aghaidh go huathoibríoch go dtí an chéad chárta eile tar éis duit freagra a thabhairt. Fanann freagraí cearta 1s, agus fanann cinn mhíchearta 2s chun ligean duit athbhreithniú a dhéanamh.'),
  ('ga', 'doc_math_title', 'Ábhair Mhatamaiticiúla'),
  ('ga', 'doc_math_desc', 'Úsáideann ábhair mhatamaiticiúla innill speisialaithe chun léirshamhlú cártaí a ghiniúint i bhfíor-am. Tá modhanna foghlama agus tástála uathúla ag na hábhair seo atá in oiriúint do choincheapa matamaiticiúla ar leith.'),
  ('ga', 'doc_organization_title', 'Ábhar a Eagrú'),
  ('ga', 'doc_organization_desc', 'Bain úsáid as Fillteáin chun Ábhair ghaolmhara a ghrúpáil le chéile. Is féidir leat Bailiúcháin a chruthú freisin chun Ábhair a eagrú ina gcosáin choimeádaithe.'),
  ('ga', 'doc_creation_title', 'Ábhair & Cártaí a Chruthú'),
  ('ga', 'doc_creation_desc', 'Cruthaigh do chuid Ábhar féin agus cuir Cártaí Splancacha amhairc leis. Tacaíonn gach cárta le híomhá agus comhad fuaime roghnach le haghaidh fuaimniú.'),
  ('ga', 'doc_collections_purpose_title', 'Cuspóir na mBailiúchán'),
  ('ga', 'doc_collections_purpose_desc', 'Is cosáin choimeádaithe iad bailiúcháin a ghrúpaíonn Ábhair le chéile. Nuair a thosaíonn tú seisiún ó Bhailiúchán, déanann an córas cártaí a mheascadh ó gach ábhar san áireamh chun tástáil chuimsitheach randamach a sholáthar.'),
  ('ga', 'doc_card_scope_title', 'Cá gcónaíonn cártaí'),
  ('ga', 'doc_card_scope_desc', 'Is iad na cártaí bunchlocha na foghlama agus baineann siad i gcónaí le hÁbhar ar leith. Cé gur féidir leat Ábhair a eagrú i bhFillteáin nó i mBailiúcháin, caithfidh cártaí iad féin a chruthú laistigh d''Ábhar.'),
  ('ga', 'doc_localization_ui_title', 'Aistriúcháin a Chur Leis'),
  ('ga', 'doc_localization_ui_desc', 'Chun sonraí logánta a chur leis, níl le déanamh ach sconna ar an deilbhín cód teanga (m.sh., EN, ES, FR) i gceanntásc an eagarthóra. Ligeann sé seo duit ainmneacha, tuairiscí agus ábhar cártaí sonracha a sholáthar do gach teanga a dtacaítear léi.'),
  ('ga', 'doc_localization_details_title', 'Conas a Oibríonn Logánú'),
  ('ga', 'doc_localization_details_desc', 'Is é an teanga "Domhanda" do phríomh-aisfhilleadh—is féidir í a bheith mar aon teanga a roghnaíonn tú. Má sholáthraíonn tú aistriúcháin shonracha, sáraíonn siad na sonraí Domhanda nuair a roghnaíonn úsáideoir an teanga Chomhéadain sin.'),
  ('ga', 'doc_json_title', 'Logánú JSON'),
  ('ga', 'doc_json_desc', 'Is féidir le cruthaitheoirí ardteicneolaíochta sonraí JSON a úsáid chun ainmneacha agus tuairiscí logánta a sholáthar, rud a fhágann go mbeidh rochtain ar ábhair i ngach teanga a dtacaítear léi.'),
  ('ga', 'doc_media_title', 'Teorainneacha Uaslódála Meán'),
  ('ga', 'doc_media_desc', 'Chun sioncronú tapa a chinntiú, coinnigh íomhánna faoi bhun 5MB agus comhaid fuaime faoi bhun 10MB.'),

  -- Croatian (hr)
  ('hr', 'doc_welcome_title', 'Dobrodošli u Aliolo'),
  ('hr', 'doc_welcome_desc', 'Aliolo je platforma za vizualno učenje dizajnirana da vam pomogne svladati predmete putem kartica i interaktivnog testiranja.'),
  ('hr', 'doc_pillars_title', '8 osnovnih stupova'),
  ('hr', 'doc_pillars_desc', 'Sav sadržaj u Aliolu organiziran je u 8 temeljnih stupova: Akademski i profesionalni, Svijet, Priroda, Ljudsko tijelo, Humanističke znanosti, Slobodno vrijeme, Inženjerstvo i Ostalo. Ove kategorije pružaju strukturirani okvir za sve predmete na platformi.'),
  ('hr', 'doc_leaderboard_title', 'Globalna ljestvica'),
  ('hr', 'doc_leaderboard_desc', 'Natječite se s učenicima diljem svijeta! Zaradite XP dovršavanjem sesija s karticama i penjite se na ljestvici. Vaša pozicija se ažurira u stvarnom vremenu kako svladavate nove predmete.'),
  ('hr', 'doc_friends_title', 'Prijatelji i pozivnice'),
  ('hr', 'doc_friends_desc', 'Učenje je bolje zajedno! Pozovite prijatelje u Aliolo putem svog profila. Možete pratiti napredak jedni drugih i ostati motivirani gledajući tko održava najduži niz.'),
  ('hr', 'doc_streaks_title', 'Sustav nizova'),
  ('hr', 'doc_streaks_desc', 'Dosljednost je ključ! Ispunite svoj dnevni cilj svaki dan kako biste izgradili svoj niz. Ne propustite niti jedan dan, inače će se niz resetirati.'),
  ('hr', 'doc_goals_title', 'Dnevni ciljevi'),
  ('hr', 'doc_goals_desc', 'Postavite svoj dnevni cilj dovršetka kartica u postavkama. Promjene vašeg cilja stupaju na snagu od sljedećeg dana.'),
  ('hr', 'doc_public_title', 'Javno naspram privatno'),
  ('hr', 'doc_public_desc', 'Predmeti mogu biti privatni (vidljivi samo vama) ili javni. Javni sadržaj dijeli se s cijelom Aliolo zajednicom, omogućujući svima da otkriju i uče iz vaših kreacija.'),
  ('hr', 'doc_sync_title', 'Sinkronizacija u oblaku'),
  ('hr', 'doc_sync_desc', 'Vaš napredak se automatski sinkronizira s oblakom. Možete se prebacivati između web i desktop verzija bez gubitka niza.'),
  ('hr', 'doc_feedback_title', 'Sustav povratnih informacija'),
  ('hr', 'doc_feedback_desc', 'Pomozite nam da postanemo bolji! Koristite ikonu povratnih informacija (Icons.feedback) na bilo kojem predmetu ili mapi kako biste prijavili probleme. Također možete poslati opće povratne informacije o aplikaciji putem odjeljka Podrška.'),
  ('hr', 'doc_lang_title', 'Jezik učenja'),
  ('hr', 'doc_lang_desc', 'Uvijek odaberite željeni jezik učenja u gornjem izborniku prije odabira predmeta. To osigurava učitavanje ispravnog zvuka i prijevoda.'),
  ('hr', 'doc_filters_title', 'Pretraživanje i filtri'),
  ('hr', 'doc_filters_desc', 'Brzo pronađite sadržaj pomoću trake za pretraživanje. Možete filtrirati prema dobnoj skupini (rana do napredna) ili suziti pogled na određene kolekcije i mape.'),
  ('hr', 'doc_flashcards_title', 'Vizualne kartice'),
  ('hr', 'doc_flashcards_desc', 'Svaki predmet sadrži skup kartica. Iako su slike i zvuk podržani, oni su opcionalni - sadržaj može biti isključivo tekstualni ili dinamički generiran.'),
  ('hr', 'doc_study_modes_title', 'Adaptivni načini učenja'),
  ('hr', 'doc_study_modes_desc', 'Aliolo podržava različite načine testiranja na temelju vašeg sadržaja: slika-u-tekst, zvuk-u-sliku i tekst-u-zvuk. Ovaj višestruki pristup osigurava svladavanje predmeta iz svih kutova.'),
  ('hr', 'doc_testing_title', 'Interaktivno testiranje'),
  ('hr', 'doc_testing_desc', 'Izazovite se pitanjima s višestrukim izborom (MCQ). Aplikacija će automatski napredovati dok odgovarate, pomažući vam da brže učite.'),
  ('hr', 'doc_autoplay_title', 'Automatsko učenje'),
  ('hr', 'doc_autoplay_desc', 'Aplikacija može automatski prijeći na sljedeću karticu nakon što odgovorite. Točni odgovori čekaju 1 s, dok netočni čekaju 2 s kako biste ih mogli pregledati.'),
  ('hr', 'doc_math_title', 'Matematički predmeti'),
  ('hr', 'doc_math_desc', 'Matematički predmeti koriste specijalizirane mehanizme za generiranje vizualizacija kartica u stvarnom vremenu. Ovi predmeti imaju jedinstvene načine učenja i testiranja prilagođene specifičnim matematičkim konceptima.'),
  ('hr', 'doc_organization_title', 'Organiziranje sadržaja'),
  ('hr', 'doc_organization_desc', 'Koristite mape za grupiranje srodnih predmeta. Također možete kreirati kolekcije za organiziranje predmeta u odabrane staze.'),
  ('hr', 'doc_creation_title', 'Stvaranje predmeta i kartica'),
  ('hr', 'doc_creation_desc', 'Izradite vlastite predmete i dodajte vizualne kartice. Svaka kartica podržava sliku i opcionalnu audio datoteku za izgovor.'),
  ('hr', 'doc_collections_purpose_title', 'Svrha kolekcija'),
  ('hr', 'doc_collections_purpose_desc', 'Kolekcije su odabrane staze koje grupiraju predmete zajedno. Kada pokrenete sesiju iz kolekcije, sustav miješa kartice iz svih uključenih predmeta kako bi pružio sveobuhvatan test.'),
  ('hr', 'doc_card_scope_title', 'Gdje žive kartice'),
  ('hr', 'doc_card_scope_desc', 'Kartice su blokovi učenja i uvijek pripadaju određenom predmetu. Iako predmete možete organizirati u mape ili kolekcije, same kartice moraju biti kreirane unutar predmeta.'),
  ('hr', 'doc_localization_ui_title', 'Dodavanje prijevoda'),
  ('hr', 'doc_localization_ui_desc', 'Za dodavanje lokaliziranih podataka jednostavno dodirnite ikonu koda jezika (npr. EN, ES, FR) u zaglavlju uređivača. To vam omogućuje da navedete specifična imena, opise i sadržaj kartica za svaki podržani jezik.'),
  ('hr', 'doc_localization_details_title', 'Kako radi lokalizacija'),
  ('hr', 'doc_localization_details_desc', '"Globalni" jezik je vaš primarni rezervni jezik - to može biti bilo koji jezik koji odaberete. Ako navedete određene prijevode, oni će nadjačati globalne podatke samo kada korisnik odabere taj određeni jezik sučelja.'),
  ('hr', 'doc_json_title', 'JSON lokalizacija'),
  ('hr', 'doc_json_desc', 'Napredni kreatori mogu koristiti JSON podatke za pružanje lokaliziranih imena i opisa, čineći predmete dostupnima na svim podržanim jezicima.'),
  ('hr', 'doc_media_title', 'Ograničenja učitavanja medija'),
  ('hr', 'doc_media_desc', 'Kako biste osigurali brzu sinkronizaciju, neka slike budu manje od 5 MB, a audio datoteke manje od 10 MB.'),

  -- Italian (it)
  ('it', 'doc_welcome_title', 'Benvenuti su Aliolo'),
  ('it', 'doc_welcome_desc', 'Aliolo è una piattaforma di apprendimento visivo progettata per aiutarti a padroneggiare le materie attraverso flashcard e test interattivi.'),
  ('it', 'doc_pillars_title', 'I 8 pilastri fondamentali'),
  ('it', 'doc_pillars_desc', 'Tutti i contenuti di Aliolo sono organizzati in 8 pilastri fondamentali: Accademico e Professionale, Mondo, Natura, Corpo Umano, Scienze Umane, Tempo Libero, Ingegneria e Altro. Queste categorie forniscono un quadro strutturato per tutte le materie della piattaforma.'),
  ('it', 'doc_leaderboard_title', 'Classifica Globale'),
  ('it', 'doc_leaderboard_desc', 'Competi con studenti di tutto il mondo! Guadagna XP completando le sessioni di flashcard e scala la classifica. La tua posizione viene aggiornata in tempo reale man mano che padroneggi nuove materie.'),
  ('it', 'doc_friends_title', 'Amici e Inviti'),
  ('it', 'doc_friends_desc', 'Imparare è meglio in compagnia! Invita gli amici su Aliolo tramite il tuo profilo. Potete monitorare i progressi reciproci e rimanere motivati vedendo chi mantiene la striscia più lunga.'),
  ('it', 'doc_streaks_title', 'Sistema delle Strisce'),
  ('it', 'doc_streaks_desc', 'La costanza è fondamentale! Completa il tuo obiettivo quotidiano ogni giorno per costruire la tua striscia. Non saltare un giorno, altrimenti la striscia si resetterà.'),
  ('it', 'doc_goals_title', 'Obiettivi Quotidiani'),
  ('it', 'doc_goals_desc', 'Imposta il tuo obiettivo giornaliero di completamento delle flashcard nelle impostazioni. Le modifiche al tuo obiettivo avranno effetto a partire dal giorno successivo.'),
  ('it', 'doc_public_title', 'Pubblico vs Privato'),
  ('it', 'doc_public_desc', 'Le materie possono essere private (visibili solo a te) o pubbliche. I contenuti pubblici sono condivisi con l''intera comunità di Aliolo, permettendo a chiunque di scoprire e imparare dalle tue creazioni.'),
  ('it', 'doc_sync_title', 'Sincronizzazione Cloud'),
  ('it', 'doc_sync_desc', 'I tuoi progressi vengono sincronizzati automaticamente sul cloud. Puoi passare dalla versione web a quella desktop senza perdere la tua striscia.'),
  ('it', 'doc_feedback_title', 'Sistema di Feedback'),
  ('it', 'doc_feedback_desc', 'Aiutaci a migliorare! Usa l''icona di feedback (Icons.feedback) su qualsiasi Materia o Cartella per segnalare problemi. Puoi anche inviare feedback generali sull''app tramite la sezione Supporto.'),
  ('it', 'doc_lang_title', 'Lingua di Apprendimento'),
  ('it', 'doc_lang_desc', 'Seleziona sempre la tua lingua di apprendimento preferita nel menu in alto prima di scegliere una materia. Ciò garantisce il caricamento dell''audio e delle traduzioni corretti.'),
  ('it', 'doc_filters_title', 'Ricerca e Filtri'),
  ('it', 'doc_filters_desc', 'Trova rapidamente i contenuti utilizzando la barra di ricerca. Puoi filtrare per fascia d''età (da prima infanzia ad avanzata) o restringere la visualizzazione a Collezioni e Cartelle specifiche.'),
  ('it', 'doc_flashcards_title', 'Flashcard Visive'),
  ('it', 'doc_flashcards_desc', 'Ogni materia contiene un set di flashcard. Sebbene le immagini e l''audio siano supportati, sono opzionali: i contenuti possono essere puramente testuali o generati dinamicamente.'),
  ('it', 'doc_study_modes_title', 'Modalità di Studio Adattive'),
  ('it', 'doc_study_modes_desc', 'Aliolo supporta varie modalità di test basate sui tuoi contenuti: Immagine-Testo, Audio-Immagine e Testo-Audio. Questo approccio multisensoriale ti assicura di padroneggiare le materie da ogni angolazione.'),
  ('it', 'doc_testing_title', 'Test Interattivi'),
  ('it', 'doc_testing_desc', 'Mettiti alla prova con domande a scelta multipla (MCQ). L''app avanzerà automaticamente mentre rispondi, aiutandoti a imparare più velocemente.'),
  ('it', 'doc_autoplay_title', 'Apprendimento Automatico'),
  ('it', 'doc_autoplay_desc', 'L''app può passare automaticamente alla flashcard successiva dopo la tua risposta. Le risposte corrette attendono 1 secondo, mentre quelle errate attendono 2 secondi per permetterti di ripassare.'),
  ('it', 'doc_math_title', 'Materie Matematiche'),
  ('it', 'doc_math_desc', 'Le materie matematiche utilizzano motori specializzati per generare visualizzazioni di flashcard in tempo reale. Queste materie presentano modalità di apprendimento e test uniche, adattate a specifici concetti matematici.'),
  ('it', 'doc_organization_title', 'Organizzazione dei Contenuti'),
  ('it', 'doc_organization_desc', 'Usa le Cartelle per raggruppare Materie correlate. Puoi anche creare Collezioni per organizzare le Materie in percorsi curati.'),
  ('it', 'doc_creation_title', 'Creazione di Materie e Flashcard'),
  ('it', 'doc_creation_desc', 'Crea le tue Materie e aggiungi Flashcard visive. Ogni flashcard supporta un''immagine e un file audio opzionale per la pronuncia.'),
  ('it', 'doc_collections_purpose_title', 'Lo Scopo delle Collezioni'),
  ('it', 'doc_collections_purpose_desc', 'Le Collezioni sono percorsi curati che raggruppano le Materie. Quando avvii una sessione da una Collezione, il sistema mescola le flashcard di tutte le materie incluse per fornire un test completo e casuale.'),
  ('it', 'doc_card_scope_title', 'Dove si trovano le flashcard'),
  ('it', 'doc_card_scope_desc', 'Le flashcard sono i mattoni dell''apprendimento e appartengono sempre a una Materia specifica. Sebbene sia possibile organizzare le Materie in Cartelle o Collezioni, le flashcard stesse devono essere create all''interno di una Materia.'),
  ('it', 'doc_localization_ui_title', 'Aggiunta di Traduzioni'),
  ('it', 'doc_localization_ui_desc', 'Per aggiungere dati localizzati, tocca semplicemente l''icona del codice lingua (ad esempio EN, ES, FR) nell''intestazione dell''editor. Ciò ti consente di fornire nomi, descrizioni e contenuti delle flashcard specifici per ogni lingua supportata.'),
  ('it', 'doc_localization_details_title', 'Come funziona la localizzazione'),
  ('it', 'doc_localization_details_desc', 'La lingua "Globale" è il tuo fallback principale: può essere qualsiasi lingua tu scelga. Se fornisci traduzioni specifiche, queste sovrascriveranno i dati Globali solo quando un utente seleziona quella specifica lingua dell''interfaccia utente.'),
  ('it', 'doc_json_title', 'Localizzazione JSON'),
  ('it', 'doc_json_desc', 'I creatori avanzati possono utilizzare i dati JSON per fornire nomi e descrizioni localizzati, rendendo le materie accessibili in tutte le lingue supportate.'),
  ('it', 'doc_media_title', 'Limiti per il Caricamento dei Media'),
  ('it', 'doc_media_desc', 'Per garantire una sincronizzazione rapida, mantieni le immagini sotto i 5 MB e i file audio sotto i 10 MB.'),

  -- Latvian (lv)
  ('lv', 'doc_welcome_title', 'Laipni lūdzam Aliolo'),
  ('lv', 'doc_welcome_desc', 'Aliolo ir vizuāla mācību platforma, kas izstrādāta, lai palīdzētu jums apgūt mācību priekšmetus, izmantojot kartītes un interaktīvu testēšanu.'),
  ('lv', 'doc_pillars_title', '8 galvenie pīlāri'),
  ('lv', 'doc_pillars_desc', 'Viss Aliolo saturs ir sakārtots 8 pamatpīlāros: Akadēmiskais un profesionālais, Pasaule, Daba, Cilvēka ķermenis, Humanitārās zinātnes, Atpūta, Inženierzinātnes un Citi. Šīs kategorijas nodrošina strukturētu ietvaru visiem priekšmetiem visā platformā.'),
  ('lv', 'doc_leaderboard_title', 'Globālais līderu saraksts'),
  ('lv', 'doc_leaderboard_desc', 'Konkurējiet ar izglītojamajiem visā pasaulē! Nopelniet XP, pabeidzot kartīšu sesijas, un pakāpieties reitingā. Jūsu pozīcija tiek atjaunināta reāllaikā, apgūstot jaunus priekšmetus.'),
  ('lv', 'doc_friends_title', 'Draugi un ielūgumi'),
  ('lv', 'doc_friends_desc', 'Mācīties kopā ir labāk! Uzaiciniet draugus uz Aliolo, izmantojot savu profilu. Varat sekot viens otra progresam un saglabāt motivāciju, redzot, kurš saglabā garāko sēriju.'),
  ('lv', 'doc_streaks_title', 'Sēriju sistēma'),
  ('lv', 'doc_streaks_desc', 'Konsekvence ir galvenais! Katru dienu izpildiet savu ikdienas mērķi, lai izveidotu savu sēriju. Nepalaidiet garām nevienu dienu, pretējā gadījumā sērija tiks atiestatīta.'),
  ('lv', 'doc_goals_title', 'Dienas mērķi'),
  ('lv', 'doc_goals_desc', 'Iestatījumos iestatiet ikdienas kartīšu izpildes mērķi. Izmaiņas jūsu mērķī stājas spēkā no nākamās dienas.'),
  ('lv', 'doc_public_title', 'Publisks pret privātu'),
  ('lv', 'doc_public_desc', 'Priekšmeti var būt privāti (redzami tikai jums) vai publiski. Publisks saturs tiek kopīgots ar visu Aliolo kopienu, ļaujot ikvienam atklāt un mācīties no jūsu darbiem.'),
  ('lv', 'doc_sync_title', 'Mākoņa sinhronizācija'),
  ('lv', 'doc_sync_desc', 'Jūsu progress tiek automātiski sinhronizēts ar mākoni. Varat pārslēgties starp tīmekļa un darbvirsmas versijām, nezaudējot sēriju.'),
  ('lv', 'doc_feedback_title', 'Atsauksmju sistēma'),
  ('lv', 'doc_feedback_desc', 'Palīdziet mums pilnveidoties! Izmantojiet atsauksmju ikonu (Icons.feedback) jebkurā priekšmetā vai mapē, lai ziņotu par problēmām. Varat arī nosūtīt vispārīgas lietotnes atsauksmes, izmantojot sadaļu Atbalsts.'),
  ('lv', 'doc_lang_title', 'Mācību valoda'),
  ('lv', 'doc_lang_desc', 'Pirms priekšmeta izvēles augšējā izvēlnē vienmēr izvēlieties vēlamo mācību valodu. Tas nodrošina pareizā audio un tulkojumu ielādi.'),
  ('lv', 'doc_filters_title', 'Meklēšana un filtri'),
  ('lv', 'doc_filters_desc', 'Ātri atrodiet saturu, izmantojot meklēšanas joslu. Varat filtrēt pēc vecuma grupas (no agrīnas līdz padziļinātai) vai sašaurināt skatījumu uz konkrētām kolekcijām un mapēm.'),
  ('lv', 'doc_flashcards_title', 'Vizuālās kartītes'),
  ('lv', 'doc_flashcards_desc', 'Katrs priekšmets satur kartīšu komplektu. Lai gan attēli un audio tiek atbalstīti, tie nav obligāti — saturs var būt tīri tekstuāls vai dinamiski ģenerēts.'),
  ('lv', 'doc_study_modes_title', 'Adaptīvie studiju režīmi'),
  ('lv', 'doc_study_modes_desc', 'Aliolo atbalsta dažādus testēšanas režīmus, pamatojoties uz jūsu saturu: attēls-teksts, audio-attēls un teksts-audio. Šī daudzu maņu pieeja nodrošina priekšmetu apguvi no visiem rakursiem.'),
  ('lv', 'doc_testing_title', 'Interaktīva testēšana'),
  ('lv', 'doc_testing_desc', 'Izaiciniet sevi ar atbilžu variantiem (MCQ). Lietotne automātiski virzīsies uz priekšu, kad atbildēsit, palīdzot jums mācīties ātrāk.'),
  ('lv', 'doc_autoplay_title', 'Automātiskā mācīšanās'),
  ('lv', 'doc_autoplay_desc', 'Lietotne var automātiski pāriet uz nākamo kartīti pēc tam, kad esat atbildējis. Pareizās atbildes gaida 1 s, bet nepareizās - 2 s, lai jūs varētu tās pārskatīt.'),
  ('lv', 'doc_math_title', 'Matemātiskie priekšmeti'),
  ('lv', 'doc_math_desc', 'Matemātiskajos priekšmetos tiek izmantoti specializēti dzinēji, lai reāllaikā ģenerētu kartīšu vizualizācijas. Šiem priekšmetiem ir unikāli mācību un testēšanas režīmi, kas pielāgoti konkrētiem matemātiskiem jēdzieniem.'),
  ('lv', 'doc_organization_title', 'Satura organizēšana'),
  ('lv', 'doc_organization_desc', 'Izmantojiet mapes, lai grupētu saistītos priekšmetus. Varat arī izveidot kolekcijas, lai sakārtotu priekšmetus atlasītos ceļos.'),
  ('lv', 'doc_creation_title', 'Priekšmetu un kartīšu izveide'),
  ('lv', 'doc_creation_desc', 'Izveidojiet savus priekšmetus un pievienojiet vizuālās kartītes. Katra kartīte atbalsta attēlu un izvēles audio failu izrunai.'),
  ('lv', 'doc_collections_purpose_title', 'Kolekciju mērķis'),
  ('lv', 'doc_collections_purpose_desc', 'Kolekcijas ir atlasīti ceļi, kas grupē priekšmetus kopā. Sākot sesiju no kolekcijas, sistēma sajauc kartītes no visiem iekļautajiem priekšmetiem, lai nodrošinātu visaptverošu testu.'),
  ('lv', 'doc_card_scope_title', 'Kur dzīvo kartītes'),
  ('lv', 'doc_card_scope_desc', 'Kartītes ir mācību bloki un vienmēr pieder pie konkrēta priekšmeta. Lai gan varat sakārtot priekšmetus mapēs vai kolekcijās, pašas kartītes ir jāizveido priekšmetā.'),
  ('lv', 'doc_localization_ui_title', 'Tulkojumu pievienošana'),
  ('lv', 'doc_localization_ui_desc', 'Lai pievienotu lokalizētos datus, redaktora galvenē vienkārši pieskarieties valodas koda ikonai (piemēram, EN, ES, FR). Tas ļauj norādīt konkrētus nosaukumus, aprakstus un kartīšu saturu katrai atbalstītajai valodai.'),
  ('lv', 'doc_localization_details_title', 'Kā darbojas lokalizācija'),
  ('lv', 'doc_localization_details_desc', '"Globālā" valoda ir jūsu primārā rezerves valoda — tā var būt jebkura jūsu izvēlēta valoda. Ja norādāt konkrētus tulkojumus, tie aizstās globālos datus tikai tad, kad lietotājs izvēlēsies šo konkrēto saskarnes valodu.'),
  ('lv', 'doc_json_title', 'JSON lokalizacija'),
  ('lv', 'doc_json_desc', 'Uzlaboti veidotāji var izmantot JSON datus, lai sniegtu lokalizētus nosaukumus un aprakstus, padarot priekšmetus pieejamus visās atbalstītajās valodās.'),
  ('lv', 'doc_media_title', 'Multivides augšupielādes ierobežojumi'),
  ('lv', 'doc_media_desc', 'Lai nodrošinātu ātru sinhronizāciju, attēliem jābūt mazākiem par 5 MB un audio failiem - mazākiem par 10 MB.')
ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
